(function () {
  function makeButton(text, className) {
    var button = document.createElement('button');
    button.type = 'button';
    button.className = className || '';
    button.textContent = text || 'Tamam';
    return button;
  }

  function cleanup(container, onKey) {
    document.removeEventListener('keydown', onKey);
    if (container && container.parentNode) container.parentNode.removeChild(container);
    document.body.classList.remove('swal2-shown', 'swal2-height-auto');
  }

  window.Swal = {
    fire: function (options) {
      options = options || {};
      return new Promise(function (resolve) {
        var classes = options.customClass || {};
        var container = document.createElement('div');
        container.className = 'swal2-container swal2-center swal2-backdrop-show';
        container.setAttribute('role', 'dialog');
        container.setAttribute('aria-modal', 'true');

        var popup = document.createElement('div');
        popup.className = 'swal2-popup ' + (classes.popup || '');

        if (options.icon) {
          var icon = document.createElement('div');
          icon.className = 'swal2-icon swal2-' + options.icon;
          popup.appendChild(icon);
        }

        if (options.title) {
          var title = document.createElement('h2');
          title.className = 'swal2-title ' + (classes.title || '');
          title.textContent = options.title;
          popup.appendChild(title);
        }

        if (options.text || options.html) {
          var body = document.createElement('div');
          body.className = 'swal2-html-container ' + (classes.htmlContainer || '');
          if (options.html) body.innerHTML = options.html;
          else body.textContent = options.text;
          popup.appendChild(body);
        }

        var actions = document.createElement('div');
        actions.className = 'swal2-actions ' + (classes.actions || '');
        var confirm = makeButton(options.confirmButtonText || 'Tamam', classes.confirmButton);
        actions.appendChild(confirm);
        var cancel = null;
        if (options.showCancelButton) {
          cancel = makeButton(options.cancelButtonText || 'Iptal', classes.cancelButton);
          actions.appendChild(cancel);
        }
        popup.appendChild(actions);
        container.appendChild(popup);

        if (options.willOpen) options.willOpen(popup, container);

        var done = function (result) {
          if (options.willClose) {
            options.willClose(popup, container, function () {
              cleanup(container, onKey);
              resolve(result);
            });
          } else {
            cleanup(container, onKey);
            resolve(result);
          }
        };
        var onKey = function (event) {
          if (event.key === 'Escape') done({ isConfirmed: false, isDismissed: true });
        };

        confirm.addEventListener('click', function () { done({ isConfirmed: true, isDismissed: false }); });
        if (cancel) cancel.addEventListener('click', function () { done({ isConfirmed: false, isDismissed: true }); });
        container.addEventListener('click', function (event) {
          if (event.target === container) done({ isConfirmed: false, isDismissed: true });
        });

        document.body.classList.add('swal2-shown');
        if (options.heightAuto !== false) document.body.classList.add('swal2-height-auto');
        document.addEventListener('keydown', onKey);
        document.body.appendChild(container);
        if (options.didOpen) options.didOpen(popup, container);
        setTimeout(function () { confirm.focus(); }, 0);
      });
    }
  };
})();
